import React, { useState } from "react";
import { Box, Button, Container, TextField, Typography, Paper, Alert, CircularProgress } from "@mui/material";
import axios from "axios";

export default function Login() {
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [showOtp, setShowOtp] = useState(false);

  const sendOtp = async () => {
    if (!/^[6-9]\d{9}$/.test(mobile)) { setError("Invalid mobile number"); return; }
    setLoading(true);
    try {
      const res = await axios.post("http://localhost:5000/api/auth/login", { mobile, otp: "123456" });
      if (res.data.success) setSuccess(res.data.message);
      else setError(res.data.message);
    } catch (err) { setError(err.response?.data?.message || "Server error"); }
    finally { setLoading(false); setShowOtp(true); }
  };

  return (
    <Container maxWidth="sm">
      <Paper sx={{ p: 4, mt: 5 }}>
        <Typography variant="h4" align="center">Rider App</Typography>
        {error && <Alert severity="error">{error}</Alert>}
        {success && <Alert severity="success">{success}</Alert>}
        <Box>
          <TextField fullWidth label="Mobile" value={mobile} onChange={e => setMobile(e.target.value)} margin="normal" />
          {showOtp && <TextField fullWidth label="OTP" value={otp} onChange={e => setOtp(e.target.value)} margin="normal" />}
          <Button fullWidth variant="contained" onClick={sendOtp} disabled={loading}>
            {loading ? <CircularProgress size={24} /> : (showOtp ? "Verify OTP" : "Send OTP")}
          </Button>
        </Box>
      </Paper>
    </Container>
  );
}
